DROP TABLE IF EXISTS public.nfl_coach_bye_matchups;
CREATE TABLE public.nfl_coach_bye_matchups (id serial PRIMARY KEY, season int, week int, game_date date, away_team text, away_coach text, away_spot text, away_prior_pct numeric, away_prior_n int, home_team text, home_coach text, home_spot text, home_prior_pct numeric, home_prior_n int, home_line numeric, home_cover int, edge_team text, edge_covered int, valid_wf int);
ALTER TABLE public.nfl_coach_bye_matchups ENABLE ROW LEVEL SECURITY;
CREATE POLICY read_all ON public.nfl_coach_bye_matchups FOR SELECT USING (true);
